// src/action/output.ts
async function setOutputs(inp) {
  const { release, inputs } = inp;
  if (release) {
    setOutput("releaseID", release.data.id.toString());
    setOutput("releaseBrowserURL", release.data.html_url);
    setOutput("releaseAPIURL", release.data.url);
    setOutput("releaseUploadURL", release.data.upload_url);
    setOutput("releaseAssetsURL", release.data.assets_url);
  }
  setOutput("body", inputs.release.body);
  const tag = inputs.tag.prefix + inputs.tag.separator + inputs.tag.base;
  setOutput("tag", tag);
  setOutput("tagPrefix", inputs.tag.prefix);
  setOutput("tagBase", inputs.tag.base);
  setOutput("tagSeparator", inputs.tag.separator);
}

// index.ts
async function run() {
  try {
    const baseRepoData = getRepoData();
    const { octokit, repoData } = await authGithubApp({ baseRepoData });
    const inputs = await getInputs({ api: octokit, repoData });
    const releaseResponse = await writeRelease({ inputs, api: octokit, repoData });
    await storeReleaseData({ inputs, api: octokit, repoData });
    await uploadFiles({ api: octokit, inputs, release: releaseResponse, repoData });
    await sendWebhook({ inputs, api: octokit, repoData, releaseResponse });
    await setOutputs({ release: releaseResponse, inputs });
    console.log(`Release finished`);
  } catch (error2) {
    console.log(error2.message);
    setFailed(error2.message);
  }
}
run();
